from flask import Flask, request, jsonify
import hashlib
import pyotp

app = Flask(__name__)

# Mock database with user info
users_db = {
    "user1": {"password_hash": hashlib.sha256(b"password123").hexdigest(), "mfa_enabled": True, "otp_secret": "JBSWY3DPEHPK3PXP"},
    "user2": {"password_hash": hashlib.sha256(b"apiaccess").hexdigest(), "mfa_enabled": False}
}

# Function to verify user password
def verify_password(username, password):
    user = users_db.get(username)
    if user:
        return hashlib.sha256(password.encode()).hexdigest() == user['password_hash']
    return False

# Function to verify OTP
def verify_otp(username, otp):
    user = users_db.get(username)
    if user and user['mfa_enabled']:
        totp = pyotp.TOTP(user['otp_secret'])
        return totp.verify(otp)
    return False

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')

    if not verify_password(username, password):
        return jsonify({"status": "error", "message": "Invalid username or password"}), 401

    user = users_db.get(username)
    if user['mfa_enabled']:
        otp = data.get('otp')
        if not otp or not verify_otp(username, otp):
            return jsonify({"status": "error", "message": "Invalid or missing OTP"}), 401
        return jsonify({"status": "success", "message": "MFA authentication successful"}), 200

    return jsonify({"status": "success", "message": "Logged in successfully"}), 200

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    data = request.json
    username = data.get('username')
    password = data.get('password')

    if not verify_password(username, password):
        return jsonify({"status": "error", "message": "Invalid username or password"}), 401

    return jsonify({"status": "success", "message": "API login successful"}), 200

